public static long solve(long[][] points) {
    final long MOD = 1000000007;
    long count = 0;
    Map<String, Integer> lineCount = new HashMap<>();

    // Group points by their y-coordinate to find horizontal lines
    Map<Long, Integer> yCount = new HashMap<>();
    for (long[] point : points) {
        long y = point[1];
        yCount.put(y, yCount.getOrDefault(y, 0) + 1);
    }

    // Calculate combinations of horizontal lines (C(m,2) for each y with m >= 2)
    for (int m : yCount.values()) {
        if (m >= 2) {
            count = (count + m * (m - 1L) / 2) % MOD;
        }
    }

    // Now, for non-horizontal lines (slopes not zero), we need to find pairs of lines with same slope
    // and same distance between them (for trapezoid)
    // But since the problem requires at least one pair of horizontal lines, we can skip this part
    // as the above already counts the cases where two pairs are horizontal

    // However, the problem allows trapezoids with one pair of horizontal lines and another pair non-horizontal
    // So we need to consider cases where one pair is horizontal and another pair is parallel (same slope)

    // So, first, we need to find all lines (non-horizontal) and group them by slope
    Map<String, Integer> slopeCount = new HashMap<>();
    for (int i = 0; i < points.length; i++) {
        for (int j = i + 1; j < points.length; j++) {
            long x1 = points[i][0], y1 = points[i][1];
            long x2 = points[j][0], y2 = points[j][1];
            if (y1 == y2) continue; // skip horizontal lines

            long dx = x2 - x1;
            long dy = y2 - y1;
            long gcd = gcd(dx, dy);
            dx /= gcd;
            dy /= gcd;

            String key = dx + "," + dy;
            slopeCount.put(key, slopeCount.getOrDefault(key, 0) + 1);
        }
    }

    // For each slope, calculate C(k,2) and multiply by count of horizontal lines (from yCount)
    for (int k : slopeCount.values()) {
        if (k >= 2) {
            for (int m : yCount.values()) {
                if (m >= 2) {
                    count = (count + (long) k * (k - 1) / 2 % MOD * m % MOD * (m - 1) / 2 % MOD) % MOD;
                }
            }
        }
    }

    return count;
}

private static long gcd(long a, long b) {
    return b == 0 ? a : gcd(b, a % b);
