    Map<Long, Integer> yCount = new HashMap<>();
    for (long[] point : points) {
        long y = point[1];
        yCount.put(y, yCount.getOrDefault(y, 0) + 1);
    }

    // Calculate combinations of two horizontal lines (parallel lines)
    for (int cnt : yCount.values()) {
        if (cnt >= 2) {
            count = (count + (long) cnt * (cnt - 1) / 2 % MOD) % MOD;
        }
    }

    // Now, for each pair of points, calculate the line (y = kx + b) they form
    // and count the number of parallel lines (same k)
    for (int i = 0; i < points.length; i++) {
        for (int j = i + 1; j < points.length; j++) {
            long x1 = points[i][0], y1 = points[i][1];
            long x2 = points[j][0], y2 = points[j][1];

            if (y1 == y2) {
                continue; // horizontal lines already counted above
            }

            // To avoid floating points, represent the slope as a reduced fraction (dx, dy)
            long dx = x2 - x1;
            long dy = y2 - y1;
            long gcd = gcd(dx, dy);
            dx /= gcd;
            dy /= gcd;

            // Also represent the intercept to ensure lines are parallel but not the same
            // For line equation: dy * x - dx * y + C = 0
            // C = dx * y1 - dy * x1
            long C = dx * y1 - dy * x1;

            // Key combines slope (dx, dy) and intercept C to distinguish parallel lines
            String key = dx + "," + dy + "," + C;
            lineCount.put(key, lineCount.getOrDefault(key, 0) + 1);
        }
    }

    // For each group of parallel lines (same slope), count the number of trapezoids
    Map<String, Integer> slopeCount = new HashMap<>();
    for (Map.Entry<String, Integer> entry : lineCount.entrySet()) {
        String key = entry.getKey();
        String[] parts = key.split(",");
        String slopeKey = parts[0] + "," + parts[1]; // Only slope (dx, dy)
        slopeCount.put(slopeKey, slopeCount.getOrDefault(slopeKey, 0) + entry.getValue());
    }

    for (int cnt : slopeCount.values()) {
        if (cnt >= 2) {
            count = (count + (long) cnt * (cnt - 1) / 2 % MOD) % MOD;
        }
    }

    return count;
}

private static long gcd(long a, long b) {
    while (b != 0) {
        long temp = b;
        b = a % b;
        a = temp;
    }
    return a;
